 24	type PerformanceGraphProps = {
 25	  dataPoints: DataPoint[][];
 26	  loading: boolean;
 27	  loadError: boolean;
 28	  metricType: string;
 29	};
 30	
 31	const PerformanceGraph: React.FC<PerformanceGraphProps> = ({
 32	  dataPoints,
 33	  loading,
 34	  loadError,
 35	  metricType,
 36	}) => {
 37	  const { t } = useCustomTranslation();
 38	  const [getDataArray, putDataArray] = dataPoints;
 39	  const [containerRef, width] = useRefWidth();
 40	  const humanize =
 41	    metricType === Metrics.BANDWIDTH
 42	      ? humanizeDecimalBytesPerSec
 43	      : humanizeSeconds;
 44	  const getData = getDataArray?.map(convertNaNToNull);
 45	  const putData = putDataArray?.map(convertNaNToNull);
 46	  const PUTLatestValue = humanize(getLatestValue(putData)).string;
 47	  const GETLatestValue = humanize(getLatestValue(getData)).string;
 48	
 49	  const legends = [
 50	    { name: t('GET {{GETLatestValue}}', { GETLatestValue }) },
 51	    { name: t('PUT {{PUTLatestValue}}', { PUTLatestValue }) },
 52	  ];
 53	
 54	  const emptyData = dataPoints.some(_.isEmpty);
 55	
 56	  if (loadError || emptyData) {
 57	    return <GraphEmpty />;
 58	  }
 59	  if (!loading) {
 60	    return (
 61	      <>
 62	        <div className="nb-data-consumption-card__chart-label text-secondary">
 63	          {CHART_LABELS(metricType, t)}
 64	        </div>
 65	        <PrometheusGraph
 66	          ref={containerRef}
 67	          className={classNames({
 68	            'nb-perf__graph--short': metricType === Metrics.LATENCY,
 69	            'nb-perf__graph--long': metricType === Metrics.BANDWIDTH,
 70	          })}
 71	        >
 72	          <Chart
 73	            ariaTitle="RGW Performance Graph"
 74	            domainPadding={{ y: 20 }}
 75	            containerComponent={
 76	              <ChartVoronoiContainer
 77	                voronoiDimension="x"
 78	                labelComponent={
 79	                  <ChartTooltip style={{ fontSize: 14, padding: 5 }} />
 80	                }
 81	                labels={({ datum }) =>
 82	                  `${humanize(datum.y).string} at ${twentyFourHourTime(
 83	                    datum.x
 84	                  )}`
 85	                }
 86	              />
 87	            }
 88	            themeColor={ChartThemeColor.multi}
 89	            scale={{ x: 'time', y: 'linear' }}
 90	            height={493}
 91	            width={width}
 92	            padding={{ top: 15, bottom: 30, left: 60, right: 30 }}
 93	            legendPosition="bottom-left"
 94	            legendComponent={
 95	              <ChartLegend
 96	                data={legends}
 97	                themeColor={ChartThemeColor.multi}
 98	                orientation="horizontal"
 99	                rowGutter={{ top: 0, bottom: 1 }}
100	                itemsPerRow={2}
101	                style={{
102	                  labels: { fontSize: 15 },
103	                }}
104	                padding={{
105	                  bottom: 50,
106	                  left: 30,
107	                  right: 20,
108	                  top: 30,
109	                }}
110	              />
111	            }
112	          >
113	            <ChartAxis offsetX={0} tickFormat={(x) => twentyFourHourTime(x)} />
114	            <ChartAxis dependentAxis tickFormat={(x) => humanize(x).string} />
115	            <ChartGroup>
116	              <ChartLine data={getData} />
117	              <ChartLine data={putData} />
118	            </ChartGroup>
119	          </Chart>
120	        </PrometheusGraph>
121	      </>
122	    );
123	  }
124	  return (
125	    <>
126	      <div className="skeleton-text nb-data-consumption-card__chart-skeleton" />
127	      <GraphEmpty height={200} loading />
128	      <div className="skeleton-text nb-data-consumption-card__chart-legend-skeleton" />
129	    </>
130	  );
131	};
132	
133	export default PerformanceGraph;

